head.b:skin:
/* =====================================================
   ДОРОГИ ВРЕМЁН — Blogger Theme
   ===================================================== */

/* Скрытая секция-ловушка для дефолтных Blogger виджетов */
.rot-hidden-section{display:none!important}
/* Layout hide in Blogger editor */
body#layout .rot-hero{display:none}
body#layout .rot-slider{display:none}
body#layout .rot-featured-museum{display:none}
body#layout .rot-choose-path{display:none}
body#layout #rot-header-nav{display:none}
body#layout .rot-footer-top{display:none}

/* === RESET & BASE === */
*{box-sizing:border-box;margin:0;padding:0}
body{background-color:#0f0e09;color:#c8c0a8;font-family:'PT Sans',Arial,sans-serif;font-size:14px;line-height:1.6}
a{color:#c9a84c;text-decoration:none}
a:hover{color:#e2c06a}
a img{border:0}
/* img reset ТОЛЬКО для наших контейнеров — не трогаем Blogger-иконки */
a img{border:0}
.clearfix::after{content:'';display:table;clear:both}

/* === CONTAINER === */
.rot-container{max-width:1100px;margin:0 auto;padding:0 15px}

/* === HEADER === */
#rot-header{background:#1e1d14;border-bottom:2px solid #8a6f2e;position:sticky;top:0;z-index:1000}
.rot-header-inner{display:flex;align-items:center;height:60px;gap:30px;max-width:1100px;margin:0 auto;padding:0 15px}
.rot-logo{display:flex;align-items:center;gap:10px;text-decoration:none;flex-shrink:0}
.rot-logo-emblem{width:36px;height:36px;border:2px solid #c9a84c;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:16px;color:#c9a84c;font-family:'PT Mono',monospace;flex-shrink:0}
.rot-logo-title{font-family:'Oswald',sans-serif;font-size:15px;font-weight:600;color:#e2c06a;letter-spacing:1px;line-height:1.1;text-transform:uppercase;display:block}
.rot-logo-sub{font-size:9px;color:#7a7060;letter-spacing:2px;text-transform:uppercase;font-family:'PT Mono',monospace;display:block}
#rot-header-nav{flex:1}
#rot-header-nav ul{display:flex;list-style:none;gap:2px}
#rot-header-nav a{display:block;padding:8px 14px;font-family:'Oswald',sans-serif;font-size:13px;letter-spacing:1.5px;text-transform:uppercase;color:#c8c0a8;border-bottom:2px solid transparent;transition:color .2s,border-color .2s}
#rot-header-nav a:hover,.rot-nav-active a{color:#c9a84c;border-bottom-color:#c9a84c}
.rot-header-icons{display:flex;align-items:center;gap:10px;flex-shrink:0}
.rot-icon-btn{background:none;border:1px solid #3a3520;color:#7a7060;width:32px;height:32px;border-radius:3px;cursor:pointer;font-size:14px;display:flex;align-items:center;justify-content:center;transition:color .2s,border-color .2s}
.rot-icon-btn:hover{color:#c9a84c;border-color:#8a6f2e}

/* === HERO SLIDER === */
.rot-hero{position:relative;width:100%;height:480px;overflow:hidden;background:#000}
.rot-slides{position:relative;width:100%;height:100%}
.rot-slide{position:absolute;inset:0;opacity:0;transition:opacity .8s ease}
.rot-slide.active{opacity:1}
.rot-slide img{display:block;width:100%;height:100%;object-fit:cover;object-position:center 40%;filter:brightness(.42)}
.rot-slide::after{content:'';position:absolute;inset:0;background:linear-gradient(to right,rgba(10,9,5,.93) 0%,rgba(10,9,5,.58) 45%,rgba(10,9,5,.08) 100%)}
.rot-hero-content{position:absolute;top:50%;left:0;transform:translateY(-50%);width:100%;z-index:10}
.rot-hero-eyebrow{font-family:'PT Mono',monospace;font-size:11px;letter-spacing:3px;text-transform:uppercase;color:#8a6f2e;margin-bottom:8px}
.rot-hero-title{font-family:'Oswald',sans-serif;font-size:54px;font-weight:700;line-height:1.0;color:#e8e0cc;text-transform:uppercase;letter-spacing:2px;margin-bottom:14px;max-width:540px;text-shadow:0 2px 20px rgba(0,0,0,.8)}
.rot-hero-desc{font-size:14px;color:#c8c0a8;max-width:420px;line-height:1.65;margin-bottom:28px}
.rot-hero-buttons{display:flex;gap:12px;flex-wrap:wrap}
.rot-btn{display:inline-flex;align-items:center;gap:8px;padding:10px 22px;font-family:'Oswald',sans-serif;font-size:13px;letter-spacing:1.5px;text-transform:uppercase;border:1px solid;cursor:pointer;transition:all .2s;text-decoration:none}
.rot-btn-primary{background:#c9a84c;border-color:#c9a84c;color:#0f0e09;font-weight:600}
.rot-btn-primary:hover{background:#e2c06a;border-color:#e2c06a;color:#0f0e09}
.rot-btn-outline{background:transparent;border-color:#7a7060;color:#c8c0a8}
.rot-btn-outline:hover{border-color:#8a6f2e;color:#c9a84c}
.rot-hero-geo{position:absolute;bottom:18px;right:20px;z-index:10;display:flex;align-items:center;gap:6px;font-family:'PT Mono',monospace;font-size:10px;letter-spacing:1px;color:#7a7060;background:rgba(10,9,5,.7);padding:5px 10px;border:1px solid #252418}
.rot-pager{position:absolute;bottom:22px;left:50%;transform:translateX(-50%);z-index:10;display:flex;gap:8px}
.rot-pager span{width:28px;height:3px;background:rgba(201,168,76,.3);cursor:pointer;transition:background .2s}
.rot-pager span.active{background:#c9a84c}
.rot-arrow{position:absolute;top:50%;transform:translateY(-50%);z-index:10;background:rgba(10,9,5,.6);border:1px solid #3a3520;color:#7a7060;width:40px;height:40px;display:flex;align-items:center;justify-content:center;cursor:pointer;font-size:18px;transition:all .2s;user-select:none}
.rot-arrow:hover{background:rgba(201,168,76,.15);border-color:#8a6f2e;color:#c9a84c}
.rot-arrow-prev{left:20px}
.rot-arrow-next{right:20px}

/* === MAIN LAYOUT === */
#rot-main-layout{max-width:1100px;margin:24px auto 0;padding:0 15px;display:grid;grid-template-columns:1fr 300px;gap:24px;align-items:start}
/* min-width:0 — обязательно для грид-ячеек, иначе контент выбивает колонку */
#rot-main-content,#rot-sidebar{min-width:0;width:100%}

/* === SECTION HEADERS === */
.rot-section-header{display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;padding-bottom:10px;border-bottom:1px solid #3a3520}
.rot-section-title{font-family:'Oswald',sans-serif;font-size:16px;font-weight:500;text-transform:uppercase;letter-spacing:2px;color:#e8e0cc;display:flex;align-items:center;gap:8px}
.rot-section-title::before{content:'';display:inline-block;width:3px;height:16px;background:#c9a84c;flex-shrink:0}
.rot-section-link{font-family:'PT Mono',monospace;font-size:10px;letter-spacing:1.5px;text-transform:uppercase;color:#7a7060;border:1px solid #252418;padding:4px 10px;transition:color .2s,border-color .2s}
.rot-section-link:hover{color:#c9a84c;border-color:#8a6f2e}

/* === POST CARDS === */
#rot-latest-posts{margin-bottom:28px}
.rot-posts-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:16px}
.rot-post-card{background:#1a1a0e;border:1px solid #252418;overflow:hidden;transition:border-color .2s}
.rot-post-card:hover{border-color:#8a6f2e}
.rot-card-thumb{position:relative;height:160px;overflow:hidden}
.rot-card-thumb img{display:block;width:100%;height:100%;object-fit:cover;transition:transform .4s ease}
.rot-post-card:hover .rot-card-thumb img{transform:scale(1.05)}
.rot-tag{position:absolute;top:10px;left:10px;font-family:'PT Mono',monospace;font-size:9px;letter-spacing:1.5px;text-transform:uppercase;padding:3px 8px;z-index:2}
.rot-tag-art{background:#2a0f0f;color:#ae6a5a;border:1px solid #ae6a5a}
.rot-tag-mus{background:#0f1a2e;color:#5a80ae;border:1px solid #5a80ae}
.rot-tag-exp{background:#0f2318;color:#5a9e70;border:1px solid #5a9e70}
.rot-tag-his{background:#1a1428;color:#8a7ab8;border:1px solid #8a7ab8}
.rot-card-body{padding:14px}
.rot-card-title{font-family:'Oswald',sans-serif;font-size:16px;font-weight:500;color:#e8e0cc;line-height:1.25;margin-bottom:8px}
.rot-card-title a{color:inherit;transition:color .2s}
.rot-card-title a:hover{color:#c9a84c}
.rot-card-excerpt{font-size:12px;color:#7a7060;line-height:1.55;margin-bottom:12px;display:-webkit-box;-webkit-line-clamp:3;-webkit-box-orient:vertical;overflow:hidden}
.rot-card-meta{display:flex;align-items:center;gap:12px;font-family:'PT Mono',monospace;font-size:10px;color:#7a7060;border-top:1px solid #252418;padding-top:10px}

/* === FEATURED MUSEUM === */
.rot-featured-museum{margin-bottom:28px;background:#1a1a0e;border:1px solid #252418;overflow:hidden}
.rot-museum-header{display:flex;align-items:center;justify-content:space-between;padding:10px 14px;background:#232318;border-bottom:1px solid #3a3520}
.rot-museum-inner{display:grid;grid-template-columns:340px 1fr}
.rot-museum-photo{height:220px;overflow:hidden}
.rot-museum-photo img{display:block;width:100%;height:100%;object-fit:cover}
.rot-museum-body{padding:22px 24px;display:flex;flex-direction:column;justify-content:space-between}
.rot-museum-label{font-family:'PT Mono',monospace;font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#8a6f2e;margin-bottom:6px}
.rot-museum-title{font-family:'Oswald',sans-serif;font-size:22px;font-weight:600;color:#e8e0cc;margin-bottom:10px;line-height:1.2}
.rot-museum-desc{font-size:13px;color:#c8c0a8;line-height:1.65;margin-bottom:16px}
.rot-museum-stats{display:flex;gap:24px;margin-bottom:18px}
.rot-stat{display:flex;flex-direction:column;align-items:center;gap:3px}
.rot-stat-icon{font-size:18px;opacity:.7}
.rot-stat-val{font-family:'Oswald',sans-serif;font-size:13px;color:#c9a84c}
.rot-stat-label{font-size:9px;color:#7a7060;letter-spacing:1px;text-transform:uppercase;font-family:'PT Mono',monospace}

/* === CHOOSE PATH === */
.rot-choose-path{margin-bottom:28px}
.rot-path-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}
.rot-path-card{background:#1a1a0e;border:1px solid #252418;padding:22px 16px;text-align:center;cursor:pointer;transition:border-color .2s,background .2s;text-decoration:none;display:block}
.rot-path-card:hover{border-color:#8a6f2e;background:#232318}
.rot-path-icon{font-size:28px;margin-bottom:10px;display:block}
.rot-path-title{font-family:'Oswald',sans-serif;font-size:14px;font-weight:500;text-transform:uppercase;letter-spacing:1.5px;color:#e8e0cc;margin-bottom:5px}
.rot-path-desc{font-size:11px;color:#7a7060;line-height:1.4}

/* === BLOG PAGER === */
.blog-pager{display:flex;justify-content:space-between;align-items:center;padding:16px 0;border-top:1px solid #3a3520;margin-top:10px}
.blog-pager a{font-family:'Oswald',sans-serif;font-size:12px;letter-spacing:1px;text-transform:uppercase;color:#7a7060;border:1px solid #252418;padding:6px 14px;transition:color .2s,border-color .2s}
.blog-pager a:hover{color:#c9a84c;border-color:#8a6f2e}

/* === SIDEBAR === */
/* flex пробрасываем вглубь: aside > section(b:section) > .widget */
#rot-sidebar{min-width:0}
#rot-sidebar .section{display:flex;flex-direction:column;gap:18px;min-width:0}
/* Любой виджет, который Blogger добавит через Layout, получит наш стиль */
#rot-sidebar .widget{min-width:0;max-width:100%;overflow:hidden}
/* Blog Archive и другие дефолтные виджеты без rot-widget обёртки */
#rot-sidebar .widget:not(:has(.rot-widget)){background:#1a1a0e;border:1px solid #252418}
#rot-sidebar .widget h2,#rot-sidebar .widget h3{background:#232318;border-bottom:1px solid #3a3520;padding:10px 14px;font-family:'Oswald',sans-serif;font-size:13px;font-weight:500;text-transform:uppercase;letter-spacing:2px;color:#c9a84c;margin:0}
#rot-sidebar .widget-content{padding:12px 14px;font-size:12px;color:#c8c0a8}
#rot-sidebar .widget-content a{color:#c8c0a8;transition:color .2s}
#rot-sidebar .widget-content a:hover{color:#c9a84c}
/* Blog Archive специфичные стили */
#rot-sidebar .BlogArchive .widget-content ul{list-style:none;padding:0;margin:0}
#rot-sidebar .BlogArchive .widget-content li{padding:4px 0;border-bottom:1px solid #252418;font-size:12px}
#rot-sidebar .BlogArchive .widget-content li:last-child{border-bottom:none}
/* Убираем дефолтные Blogger-стрелки-изображения из Archive */
#rot-sidebar .BlogArchive img{display:none}
/* Кастомный Archive внутри rot-widget */
.rot-archive-year{display:flex;justify-content:space-between;align-items:center;padding:5px 0;border-bottom:1px solid #3a3520;font-family:'Oswald',sans-serif;font-size:13px;color:#c9a84c}
.rot-archive-month{display:flex;justify-content:space-between;align-items:center;padding:4px 0 4px 12px;border-bottom:1px solid #252418;font-size:12px;color:#c8c0a8}
.rot-archive-year a,.rot-archive-month a{color:inherit;text-decoration:none;transition:color .2s}
.rot-archive-year a:hover,.rot-archive-month a:hover{color:#c9a84c}
/* СКРЫВАЕМ секцию-ловушку для дефолтных виджетов */
.rot-hidden-section{display:none!important}
/* Скрываем Attribution виджет который Blogger часто добавляет */
.widget.Attribution{display:none!important}
.rot-widget{background:#1a1a0e;border:1px solid #252418;overflow:hidden}
.rot-widget-header{background:#232318;border-bottom:1px solid #3a3520;padding:10px 14px;font-family:'Oswald',sans-serif;font-size:13px;font-weight:500;text-transform:uppercase;letter-spacing:2px;color:#c9a84c;display:flex;align-items:center;gap:8px}
.rot-widget-header::before{content:'';width:2px;height:13px;background:#c9a84c;flex-shrink:0}
.rot-widget-body{padding:14px}
.rot-map-placeholder{height:160px;background:#0a1008;border:1px solid #252418;display:flex;align-items:center;justify-content:center;color:#7a7060;font-family:'PT Mono',monospace;font-size:10px;letter-spacing:1px;text-align:center;padding:20px;line-height:1.8}
.rot-road-item{display:flex;align-items:flex-start;gap:10px;padding:10px 0;border-bottom:1px solid #252418}
.rot-road-item:last-child{border-bottom:none}
.rot-road-flag{font-size:20px;flex-shrink:0}
.rot-road-country{font-family:'Oswald',sans-serif;font-size:13px;color:#e8e0cc}
.rot-road-date{font-family:'PT Mono',monospace;font-size:10px;color:#7a7060;margin-top:2px}
.rot-road-link{font-size:10px;color:#8a6f2e;text-transform:uppercase;letter-spacing:1px;font-family:'PT Mono',monospace;margin-top:4px;display:inline-block}
.rot-quote-text{font-style:italic;font-size:13px;line-height:1.7;color:#c8c0a8;border-left:2px solid #8a6f2e;padding-left:12px;margin-bottom:10px}
.rot-quote-author{font-family:'PT Mono',monospace;font-size:10px;color:#8a6f2e;letter-spacing:1px;text-align:right}
.rot-tags-list{list-style:none}
.rot-tags-list li{display:flex;align-items:center;justify-content:space-between;padding:6px 0;border-bottom:1px solid #252418;font-size:12px}
.rot-tags-list li:last-child{border-bottom:none}
.rot-tags-list a{color:#c8c0a8;transition:color .2s}
.rot-tags-list a:hover{color:#c9a84c}
.rot-tag-count{font-family:'PT Mono',monospace;font-size:10px;color:#7a7060;background:#232318;padding:1px 7px;border-radius:2px}
.rot-subscribe-text{font-size:12px;color:#7a7060;margin-bottom:12px;line-height:1.55}
.rot-sub-form{display:flex;gap:6px}
.rot-sub-input{flex:1;background:#232318;border:1px solid #3a3520;color:#c8c0a8;padding:8px 10px;font-size:12px;font-family:'PT Sans',sans-serif;outline:none}
.rot-sub-input:focus{border-color:#8a6f2e}
.rot-sub-btn{background:#c9a84c;border:none;color:#0f0e09;padding:8px 14px;font-family:'Oswald',sans-serif;font-size:12px;letter-spacing:1px;cursor:pointer;transition:background .2s}
.rot-sub-btn:hover{background:#e2c06a}
.rot-socials{display:flex;gap:8px;margin-top:12px}
.rot-social-btn{flex:1;background:#232318;border:1px solid #3a3520;color:#7a7060;padding:7px;text-align:center;font-size:12px;cursor:pointer;text-decoration:none;transition:border-color .2s,color .2s;font-family:'Oswald',sans-serif;letter-spacing:1px}
.rot-social-btn:hover{border-color:#8a6f2e;color:#c9a84c}

/* === FOOTER === */
#rot-footer{margin-top:48px;background:#1e1d14;border-top:2px solid #3a3520}
.rot-footer-top{max-width:1100px;margin:0 auto;padding:36px 15px 28px;display:grid;grid-template-columns:240px 1fr 1fr 1fr;gap:32px}
.rot-footer-desc{font-size:12px;color:#7a7060;line-height:1.65;margin-top:12px}
.rot-footer-col-title{font-family:'Oswald',sans-serif;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:2px;color:#8a6f2e;margin-bottom:12px;padding-bottom:6px;border-bottom:1px solid #252418}
.rot-footer-links{list-style:none;display:flex;flex-direction:column;gap:7px}
.rot-footer-links a{font-size:12px;color:#7a7060;transition:color .2s}
.rot-footer-links a:hover{color:#c9a84c}
.rot-footer-bottom{border-top:1px solid #252418;padding:14px 15px;max-width:1100px;margin:0 auto;display:flex;align-items:center;justify-content:space-between;font-family:'PT Mono',monospace;font-size:10px;color:#7a7060;letter-spacing:.5px}
.rot-footer-socials{display:flex;gap:10px}
.rot-footer-socials a{color:#7a7060;font-size:13px;transition:color .2s}
.rot-footer-socials a:hover{color:#c9a84c}

head.script:
//
var thumbnail_mode = "float";
var summary_noimg = 200;
var summary_img = 200;
var img_thumb_height = 160;
var img_thumb_width = 280;

function removeHtmlTag(strx, chop) {
  var s = strx.split("<");
  for (var i = 0; i < s.length; i++) {
    s[i] = s[i].substring(s[i].indexOf(">") + 1, s[i].length);
  }
  s = s.join("");
  s = s.substring(0, chop - 3);
  return s + "...";
}

function createSummaryAndThumb(pID) {
  var div = document.getElementById(pID);
  var imgtag = "";
  var img = div.getElementsByTagName("img");
  var summ = summary_noimg;
  if (img.length >= 1) {
    imgtag = '<img src="' + img[0].src + '" class="rot-thumb-img"/>';
    summ = summary_img;
  }
  var summary = imgtag + "<div>" + removeHtmlTag(div.innerHTML, summ) + "</div>";
  div.innerHTML = summary;
}
//

body.script:
//
(function(){
  var slides = document.querySelectorAll('.rot-slide');
  var dots   = document.querySelectorAll('#rot-pager span');
  var geo    = document.getElementById('rot-hero-geo');
  if(!slides.length) return;
  var cur = 0, total = slides.length, timer;
  function goTo(n){
    slides[cur].classList.remove('active');
    if(dots[cur]) dots[cur].classList.remove('active');
    cur = (n + total) % total;
    slides[cur].classList.add('active');
    if(dots[cur]) dots[cur].classList.add('active');
    if(geo) geo.textContent = slides[cur].getAttribute('data-geo') || '';
  }
  function startAuto(){ timer = setInterval(function(){ goTo(cur+1); }, 5000); }
  function resetAuto(){ clearInterval(timer); startAuto(); }
  var prev = document.getElementById('rot-prev');
  var next = document.getElementById('rot-next');
  if(prev) prev.addEventListener('click', function(){ goTo(cur-1); resetAuto(); });
  if(next) next.addEventListener('click', function(){ goTo(cur+1); resetAuto(); });
  dots.forEach(function(d,i){ d.addEventListener('click', function(){ goTo(i); resetAuto(); }); });
  startAuto();
})();
//
